// Extract the user's question and metadata from the Slack slash command payload
const body = $input.first().json.body;
const params = new URLSearchParams(body);

const question = params.get('text') || '';

if (!question.trim()) {
  throw new Error('No question provided. Usage: /ask-data <your question>');
}

return [{
  json: {
    question: question.trim(),
    channel_id: params.get('channel_id') || '',
    user_id: params.get('user_id') || '',
    response_url: params.get('response_url') || ''
  }
}];

// Extract SQL from Groq response and validate it
const groqResponse = $input.first().json;

// Get the generated text from Groq OpenAI-compatible response
let sql = groqResponse?.choices?.[0]?.message?.content || '';

if (!sql) {
  throw new Error('Groq returned an empty response. Please try again.');
}

// Strip markdown code fences if model added them despite instructions
sql = sql.replace(/```sql/gi, '').replace(/```/g, '').trim();

// Safety check - only allow SELECT or WITH (CTE) statements
const firstToken = sql.split(/\s+/)[0].toUpperCase();
if (!['SELECT', 'WITH'].includes(firstToken)) {
  throw new Error(`Unsafe SQL blocked. Only SELECT queries are allowed. Model returned: ${firstToken}`);
}

// Pass SQL and original Slack metadata downstream
return [{
  json: {
    sql,
    question: $node['Parse Slack Payload'].json.question,
    channel_id: $node['Parse Slack Payload'].json.channel_id,
    user_id: $node['Parse Slack Payload'].json.user_id,
    response_url: $node['Parse Slack Payload'].json.response_url
  }
}];

// Format query results into a readable Slack message
const results = $input.all().map(item => item.json);
const sql = $node['Clean & Validate SQL'].json.sql;
const question = $node['Clean & Validate SQL'].json.question;
const response_url = $node['Clean & Validate SQL'].json.response_url;

// Empty result set
if (!results || results.length === 0) {
  return [{
    json: {
      message: `*📊 Query Results*\n\n*Question:* ${question}\n*Rows:* 0\n\n*SQL Used:*\n\`\`\`${sql}\`\`\`\n\nℹ️ No rows matched your query.`,
      response_url
    }
  }];
}

// Build a fixed-width ASCII table (max 10 rows preview)
const headers = Object.keys(results[0]);
const maxPreview = 10;
const preview = results.slice(0, maxPreview);

// Calculate column widths (capped at 25 chars)
const widths = headers.map(h =>
  Math.min(25, Math.max(h.length, ...preview.map(r => String(r[h] ?? 'NULL').length)))
);

const truncate = (val, w) => {
  const s = String(val ?? 'NULL');
  return s.length > w ? s.slice(0, w - 1) + '...' : s;
};

const fmtRow = vals =>
  vals.map((v, i) => truncate(v, widths[i]).padEnd(widths[i])).join(' | ');

const separator = widths.map(w => '-'.repeat(w)).join('-+-');

const lines = [
  fmtRow(headers),
  separator,
  ...preview.map(r => fmtRow(headers.map(h => r[h])))
];

if (results.length > maxPreview) {
  lines.push(`... ${results.length - maxPreview} more rows not shown`);
}

const table = lines.join('\n');

const message = [
  `*📊 Query Results*`,
  `*Question:* ${question}`,
  `*Rows Returned:* ${results.length}`,
  ``,
  `*Generated SQL:*`,
  `\`\`\`${sql}\`\`\``,
  ``,
  `*Preview:*`,
  `\`\`\`${table}\`\`\``
].join('\n');

return [{ json: { message, response_url } }];

// Build a clean error message and send it back to Slack
const error = $input.first().json?.error?.message
           || $input.first().json?.message
           || JSON.stringify($input.first().json)
           || 'Unknown error';

// Try to get response_url from whichever upstream node has it
const response_url =
  $node['Clean & Validate SQL']?.json?.response_url ||
  $node['Parse Slack Payload']?.json?.response_url ||
  '';

return [{
  json: {
    message: `❌ *Query Failed*\n\n*Error:*\n\`\`\`${error}\`\`\`\n\n💡 Try rephrasing your question or check your column names.`,
    response_url
  }
}];
